const config = window.orderConfig || {};

// Setup API Endpoint
const API_BASE_URL = 'https://api.robertwp.com/api';
const SITE_URL = 'https://robertwp.com';

const transactionId = config.transactionId || '';
const pluginSlug = config.pluginSlug || '';
const pluginVersion = config.pluginVersion || '';

// API Configuration
const API_CONFIG = {

    getDeliveryToken: `${API_BASE_URL}/auth/issue-delivery-token`,
    //
    getCustomer: `${API_BASE_URL}/paddle/customers`,
    //
    createLicense: `${API_BASE_URL}/delivery/create-license`,
    //
    wpUserSync: `${SITE_URL}/wp-json/rw-user-sync/v1/get-or-create`,
    updateUUID: `${API_BASE_URL}/delivery/update-uuid`,

    //
    getDownloadUrl: `${API_BASE_URL}/delivery/download-url`,
    //
    getLicenseKey: `${API_BASE_URL}/delivery/license-key`,
    //
    getActivationUrl: `${API_BASE_URL}/delivery/activation-url`,

    //
    sendEmail: `${API_BASE_URL}/delivery/send-email`
};
class DeliveryCompletedError extends Error {
    constructor() {
        super('DELIVERY_COMPLETED');
        this.type = 'delivery_completed';
        this.shouldIgnore = true;
    }
}
class OrderCompletePage {
    constructor(transactionId, pluginSlug, pluginVersion) {
        this.transactionId = transactionId;
        this.pluginSlug = pluginSlug;
        this.pluginVersion = pluginVersion;
        this.customerEmail = null;
        this.customerId = null;
        this.licenseId = null;
        this.uuid = null;
        this.userCreated = false;
        this.deliveryToken = null;
        this.tokenPromise = null;
        this.deliverables = {
            download: { status: 'pending', data: null },
            license: { status: 'pending', data: null },
            activation: { status: 'pending', data: null }
        };

        this.progressWeights = {
            step1: 15,
            step2: 15,
            step3: 20,
            step4: 20,
            step5: 15,
            step6: 15
        };

        // 请求队列控制
        this.requestQueue = {
            queue: [],
            isProcessing: false,
            maxRetries: 0,
            retryDelay: 3000,
            currentStep: 0
        };

        this.storageKey = `order_${this.transactionId}`;
        this.init();
    }

    async init() {
        if (!this.transactionId) {
            this.showError('Invalid Transaction ID');
            return;
        }

        // Check whether the delivery has been processed.
        const cachedData = this.getCachedData();
        if (cachedData && cachedData.completed) {
            if (cachedData.userCreated !== undefined) {
                this.userCreated = cachedData.userCreated;
            }
            if (cachedData.customerEmail) {
                this.customerEmail = cachedData.customerEmail;
            }

            document.getElementById('initial-loading').style.display = 'none';
            document.getElementById('app').style.display = 'block';
            this.renderCompletedPage(cachedData);
            return;
        }

        document.getElementById('initial-loading').style.display = 'none';
        document.getElementById('app').style.display = 'block';

        this.renderInitialPage();
        await this.processDelivery();
    }

    getCachedData() {
        try {
            const cached = sessionStorage.getItem(this.storageKey);
            return cached ? JSON.parse(cached) : null;
        } catch (e) {
            return null;
        }
    }

    cacheData(data) {
        try {
            const cacheData = {
                ...data,
                userCreated: this.userCreated,
                customerEmail: this.customerEmail,
                transactionId: this.transactionId
            };
            sessionStorage.setItem(this.storageKey, JSON.stringify(cacheData));
        } catch (e) {
            console.error('Cache failure:', e);
        }
    }

    updateStepMessage(stepId, message) {
        const stepElement = document.getElementById(stepId);
        if (stepElement) {
            const description = stepElement.querySelector('p');
            if (description) {
                description.textContent = message;
            }
        }
    }

    updateStepProgress(stepName, subProgress, message) {
        // subProgress 是0-100之间的值，表示当前步骤完成的百分比
        let completedWeight = 0;
        const steps = ['step1', 'step2', 'step3', 'step4', 'step5', 'step6'];

        for (let step of steps) {
            if (step === stepName) {
                // 当前步骤：基础进度 + 子进度
                completedWeight += (this.progressWeights[step] * subProgress / 100);
                break;
            } else {
                // 已完成步骤：加上完整权重
                completedWeight += this.progressWeights[step];
            }
        }

        this.updateProgress(Math.min(100, Math.round(completedWeight)), message);
    }

    // 队列处理方法
    async enqueueRequest(stepName, requestFn, condition = true) {
        if (!condition) {
            //console.log(`Skipping ${stepName} - condition not met`);
            return { skipped: true };
        }

        return new Promise((resolve, reject) => {
            this.requestQueue.queue.push({
                stepName,
                requestFn,
                resolve,
                reject,
                retries: 0,
                maxRetries: this.requestQueue.maxRetries
            });
            this.processQueue();
        });
    }

    async processQueue() {
        if (this.requestQueue.isProcessing || this.requestQueue.queue.length === 0) {
            return;
        }

        this.requestQueue.isProcessing = true;

        while (this.requestQueue.queue.length > 0) {
            const currentRequest = this.requestQueue.queue[0];

            try {
                const result = await currentRequest.requestFn();
                this.requestQueue.queue.shift();
                currentRequest.resolve(result);
                this.requestQueue.currentStep++;
                await this.delay(500);
            } catch (error) {
                if (currentRequest.retries < currentRequest.maxRetries) {
                    currentRequest.retries++;
                    const delayTime = this.requestQueue.retryDelay * Math.pow(2, currentRequest.retries - 1);
                    this.showRetryStatus(currentRequest.stepName, currentRequest.retries, delayTime);
                    await this.delay(delayTime);
                } else {
                    this.requestQueue.queue.shift();

                    if (error.type === 'delivery_completed' || error.message === 'DELIVERY_COMPLETED') {
                        currentRequest.reject(error);
                    } else {
                        currentRequest.reject(new Error(`${currentRequest.stepName} failed after ${currentRequest.maxRetries + 1} attempts`));
                        this.showStepFailed(currentRequest.stepName);
                    }

                    this.requestQueue.queue = [];
                    break;
                }
            }
        }

        this.requestQueue.isProcessing = false;
    }

    delay(ms) {
        return new Promise(resolve => setTimeout(resolve, ms));
    }

    showRetryStatus(stepName, retryCount, delayTime) {
        const stepMap = {
            'verifyTransaction': 'step1',
            'createLicense': 'step2',
            'syncUser': 'step3',
            'generateLicenseKey': 'step4',
            'generateDownloadUrl': 'step5',
            'generateActivationUrl': 'step6'
        };

        const stepId = stepMap[stepName];
        if (stepId) {
            const stepElement = document.getElementById(stepId);
            if (stepElement) {
                const statusSpan = stepElement.querySelector('.item-status');
                if (statusSpan) {
                    statusSpan.innerHTML = `<span class="status-spinner"></span>Retrying (${retryCount}/3)...`;
                }

                const description = stepElement.querySelector('p');
                if (description) {
                    description.textContent = `Connection issue, retrying in ${Math.round(delayTime/1000)}s...`;
                }
            }
        }
    }

    showStepFailed(stepName) {
        const stepMap = {
            'verifyTransaction': 'step1',
            'createLicense': 'step2',
            'syncUser': 'step3',
            'generateLicenseKey': 'step4',
            'generateDownloadUrl': 'step5',
            'generateActivationUrl': 'step6'
        };

        const stepId = stepMap[stepName];
        if (stepId) {
            const stepElement = document.getElementById(stepId);
            if (stepElement) {
                stepElement.classList.add('failed');
                const statusSpan = stepElement.querySelector('.item-status');
                if (statusSpan) {
                    statusSpan.textContent = 'Failed';
                    statusSpan.className = 'item-status failed';
                }
            }
        }
    }

    renderInitialPage() {
        const app = document.getElementById('app');
        app.innerHTML = `
            <div>
                <span class="status-badge status-success">✓ Payment Successful</span>
                <h1 id="mainTitle">Thank You for Your Purchase!</h1>

                <div class="transaction-id">Transaction ID: ${this.transactionId}</div>

                <div id="statusMessage" class="status-message info">
                    <p id="mainMessage">We're preparing your plugin and license information...</p>
                    <p id="subMessage" class="muted">This usually takes just a few seconds. Please don't close this page.</p>
                </div>

                <div class="progress-container">
                    <div class="progress-bar">
                        <div class="progress-fill" id="progressFill" style="width: 0%"></div>
                    </div>
                    <div class="progress-text" id="progressText">Starting...</div>
                </div>

                <div class="delivery-item generating" id="step1">
                    <div class="item-header">
                        <h3 class="item-title">1. Verifying Payment</h3>
                        <span class="item-status generating">In Progress</span>
                    </div>
                    <p>Retrieving your transaction information from Paddle...</p>
                </div>

                <div class="delivery-item" id="step2" style="opacity: 0.5;">
                    <div class="item-header">
                        <h3 class="item-title">2. Creating License Record</h3>
                        <span class="item-status">Pending</span>
                    </div>
                    <p>Setting up your license in our system...</p>
                </div>

                <div class="delivery-item" id="step3" style="opacity: 0.5;">
                    <div class="item-header">
                        <h3 class="item-title">3. Setting Up Your Account</h3>
                        <span class="item-status">Pending</span>
                    </div>
                    <p>Preparing your account for plugin access...</p>
                </div>

                <div class="delivery-item" id="step4" style="opacity: 0.5;">
                    <div class="item-header">
                        <h3 class="item-title">4. Generating License Key</h3>
                        <span class="item-status">Pending</span>
                    </div>
                    <p>Creating your unique license key...</p>
                </div>

                <div class="delivery-item" id="step5" style="opacity: 0.5;">
                    <div class="item-header">
                        <h3 class="item-title">5. Preparing Download</h3>
                        <span class="item-status">Pending</span>
                    </div>
                    <p>Getting your plugin ready for download...</p>
                </div>

                <div class="delivery-item" id="step6" style="opacity: 0.5;">
                    <div class="item-header">
                        <h3 class="item-title">6. Account Access</h3>
                        <span class="item-status">Pending</span>
                    </div>
                    <p>Preparing account access...</p>
                </div>

                <p class="muted">All resources will also be sent to your email once ready.</p>
            </div>
        `;
    }

    async processDelivery() {
        try {
            // Step 1: Get Paddle transaction information
            this.updateStep('step1', 'In Progress', 'Retrieving transaction from Paddle...');
            await this.enqueueRequest('verifyTransaction', async () => {
                await this.verifyTransaction();
            });

            // Step 2: Create license record
            this.updateStep('step2', 'In Progress', 'Creating license record...', false, true);
            await this.enqueueRequest('createLicense', async () => {
                await this.createLicense();
            });

            // Step 3: Sync / Create WordPress user
            this.updateStep('step3', 'In Progress', 'Setting up your account...', false, true);
            await this.enqueueRequest('syncUser', async () => {
                await this.syncUser();
            });

            // Step 4: Generate license key
            this.updateStep('step4', 'In Progress', 'Generating license key...', false, true);
            await this.enqueueRequest('generateLicenseKey', async () => {
                await this.generateLicenseKey();
            });

            // Step 5: Generate download link
            this.updateStep('step5', 'In Progress', 'Preparing download link...', false, true);
            await this.enqueueRequest('generateDownloadUrl', async () => {
                await this.generateDownloadUrl();
            });

            // Step 6: Generate activation link (only for new users)
            this.updateStep('step6', 'In Progress', this.userCreated ? 'Creating activation link...' : 'Checking account status...', false, true);
            await this.enqueueRequest('generateActivationUrl', async () => {
                if (this.userCreated) {
                    await this.generateActivationUrl();
                } else {
                    this.updateStep('step6', 'Not Needed', 'Existing account - no activation required', true);
                    this.deliverables.activation = { status: 'not_needed', data: null };
                    this.updateStepProgress('step6', 100, 'All resources ready');
                }
            }, true);

            await this.completeOrder();

        } catch (error) {
            if (error.type === 'delivery_completed' || error.message === 'DELIVERY_COMPLETED') {
                return;
            }
            this.handleProcessingError(error);
        }
    }

    async ensureDeliveryToken() {
        if (this.deliveryToken) {
            return;
        }

        if (this.tokenPromise) {
            await this.tokenPromise;
            return;
        }

        this.tokenPromise = this.fetchDeliveryToken();
        try {
            await this.tokenPromise;
        } catch (error) {
            if (error.delivery_status === 'completed') {
                throw error;
            }
            throw error;
        } finally {
            this.tokenPromise = null;
        }
    }

    async fetchDeliveryToken() {
        try {
            const response = await fetch(API_CONFIG.getDeliveryToken, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ transaction_id: this.transactionId })
            });

            if (!response.ok) {
                throw new Error('Failed to get delivery token');
            }

            const result = await response.json();

            const token = result.data?.token;
            const customerId = result.data?.customer_id;

            if (result.data.delivery_status === 'completed') {
                const completedError = new Error('DELIVERY_COMPLETED');
                completedError.delivery_status = 'completed';
                throw completedError;
            }

            if (!token) {
                throw new Error('No token in response');
            }

            if (!customerId) {
                throw new Error('No customer_id in response');
            }

            this.deliveryToken = token;
            this.customerId = customerId;

            return result.data.token;
        } catch (error) {
            if (error.delivery_status === 'completed') {
                throw error;
            }
            //console.error('Failed to fetch delivery token:', error);
            throw error;
        }
    }

    async verifyTransaction() {
        try {
            this.updateStepMessage('step1', 'Verifying payment with Paddle...');
            await this.ensureDeliveryToken();
            this.updateStepProgress('step1', 60, 'Payment verified');

            //
            this.updateStepMessage('step1', 'Retrieving your account information...');
            await this.getCustomerInfo();
            this.updateStepProgress('step1', 100, 'Account info retrieved');

            this.updateStep('step1', 'Complete', 'Payment verified successfully', true);

        } catch (error) {
            if (error.delivery_status === 'completed') {
                this.updateStep('step1', 'ℹ️ Notice',
                    'Your order has been processed. You will receive an email within 5-10 minutes.',
                    true
                );
                throw new DeliveryCompletedError();
            }

            let subMessage = '';

            if (error.error_code === 'transaction_not_found') {
                subMessage = 'Transaction not found';
            } else if (error.error_code === 'transaction_not_completed') {
                subMessage = 'Payment not completed';
            }

            const displayMessage = subMessage ? `Payment verification failed: ${subMessage}` : 'Payment verification failed';

            this.updateStep('step1', 'Failed', displayMessage, false);
            throw error;
        }
    }

    async createLicense() {
        try {
            this.updateStepMessage('step2', 'Creating license record in our system...');

            const response = await fetch(API_CONFIG.createLicense, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${this.deliveryToken}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    transaction_id: this.transactionId,
                    customer_id: this.customerId,
                    customer_email: this.customerEmail
                })
            });

            if (!response.ok) {
                throw new Error(`License record creation failed: ${response.status}`);
            }

            const result = await response.json();
            this.licenseId = result.data?.license_id || data.license_id;

            this.updateStepProgress('step2', 100, 'License record created');
            this.updateStep('step2', 'Complete', 'License record created successfully', true);

        } catch (error) {
            console.error('Create license record failed:', error);
            this.updateStep('step2', 'Failed', 'License record creation failed', false);
            throw error;
        }
    }

    async syncUser() {
        try {
            this.updateStepMessage('step3', 'Creating your WordPress account...');
            await this.syncWordPressUser();
            this.updateStepProgress('step3', 80, 'Account created');

            this.updateStepMessage('step3', 'Updating user information...');
            await this.updateUUID();

            this.updateStep('step3', 'Complete', 'Account ready', true);
            this.updateStepProgress('step3', 100, 'Account setup complete');

        } catch (error) {
            this.updateStep('step3', 'Failed', 'User sync failed', false);
            throw new Error(`User sync failed: ${error.message}`);
        }
    }

    async getCustomerInfo() {
        try {

            const customerResponse = await fetch(`${API_CONFIG.getCustomer}/${this.customerId}`, {
                headers: {
                    'Authorization': `Bearer ${this.deliveryToken}`,
                    'X-Transaction-ID': this.transactionId
                }
            });

            if (!customerResponse.ok) {
                const errorData = await customerResponse.json();
                throw new Error(`Customer query failed: ${customerResponse.status} - ${errorData.error || 'Unknown error'}`);
            }

            const customerData = await customerResponse.json();
            this.customerEmail = customerData.data?.email || customerData.email;

            if (!this.customerEmail) {
                throw new Error('Unable to get email from customer response');
            }

            return this.customerEmail;
        } catch (error) {
            console.error('Get customer info failed:', error);
            throw error; // 向上抛出，让 syncUser 的 catch 处理
        }
    }

    async syncWordPressUser() {
        try {
            const response = await fetch(API_CONFIG.wpUserSync, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${this.deliveryToken}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    transaction_id: this.transactionId,
                    email: this.customerEmail
                })
            });

            if (!response.ok) {
                const errorData = await response.json().catch(() => ({}));
                throw new Error(`User sync failed: ${response.status} - ${errorData.message || 'Unknown error'}`);
            }

            const result = await response.json();
            this.uuid = result.data.external_uuid;
            this.userCreated = result.data.created || false;

            if (!this.uuid) {
                throw new Error('User sync returned incorrect format: missing uuid');
            }

            return { uuid: this.uuid, userCreated: this.userCreated };
        } catch (error) {
            console.error('Sync WordPress user failed:', error);
            throw error; // 向上抛出，让 syncUser 的 catch 处理
        }
    }

    async updateUUID() {
        try {

            const response = await fetch(API_CONFIG.updateUUID, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${this.deliveryToken}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    transaction_id: this.transactionId,
                    uuid: this.uuid,
                    user_created: this.userCreated,
                    customer_email: this.customerEmail,
                    license_id: this.licenseId
                })
            });

            if (!response.ok) {
                console.error(`User data update failed: ${response.status}`);
            }

        } catch (error) {
            console.error('User data update failed:', error);
        }
    }

    async generateLicenseKey() {
        try {
            this.updateStepMessage('step4', 'Generating your license key...');

            this.updateStepProgress('step4', 20, 'License key generating...');

            const response = await fetch(`${API_CONFIG.getLicenseKey}/${this.transactionId}`, {
                headers: {
                    'Authorization': `Bearer ${this.deliveryToken}`,
                    'X-Transaction-ID': this.transactionId
                }
            });

            if (!response.ok) {
                throw new Error('Failed to generate license key');
            }

            this.updateStepProgress('step4', 70, 'License key created');

            const result = await response.json();
            this.deliverables.license = {
                status: 'ready',
                data: { key: result.data.key }
            };

            this.updateStep('step4', 'Complete', 'License key generated', true);
            this.updateStepProgress('step4', 100, 'License key ready');

        } catch (error) {
            console.error('Generate license key failed:', error);
            this.deliverables.license = { status: 'failed', data: null };
            this.updateStep('step4', 'Failed', 'License key generation failed', false);
            throw error;
        }
    }

    async generateDownloadUrl() {
        try {
            this.updateStepMessage('step5', 'Preparing your download link...');

            this.updateStepProgress('step5', 20, 'Preparing plugin package...');

            const response = await fetch(API_CONFIG.getDownloadUrl, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${this.deliveryToken}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    transaction_id: this.transactionId,
                    license_id: this.licenseId
                })
            });

            if (!response.ok) {
                throw new Error('Failed to generate download link');
            }

            this.updateStepProgress('step5', 70, 'Plugin package ready');

            const result = await response.json();
            this.deliverables.download = {
                status: 'ready',
                data: { url: result.data.url }
            };

            this.updateStep('step5', 'Complete', 'Download link ready', true);
            this.updateStepProgress('step5', 100, 'Download ready');

        } catch (error) {
            console.error('Generate download URL failed:', error);
            this.deliverables.download = { status: 'failed', data: null };
            this.updateStep('step5', 'Failed', 'Download preparation failed', false);
            throw error;
        }
    }

    async generateActivationUrl() {
        try {
            this.updateStepMessage('step6', 'Creating account activation link...');

            this.updateStepProgress('step6', 30, 'Preparing activation link...');

            const response = await fetch(API_CONFIG.getActivationUrl, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${this.deliveryToken}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    transaction_id: this.transactionId,
                    uuid: this.uuid
                })
            });

            if (!response.ok) {
                throw new Error('Failed to generate activation link');
            }

            this.updateStepProgress('step6', 70, 'Activation link created');

            const result = await response.json();
            this.deliverables.activation = {
                status: 'ready',
                data: { url: result.data.url }
            };

            this.updateStep('step6', 'Complete', 'Activation link created', true);
            this.updateStepProgress('step6', 100, 'All resources ready');

        } catch (error) {
            console.error('Generate activation URL failed:', error);
            this.deliverables.activation = { status: 'failed', data: null };
            this.updateStep('step6', 'Failed', 'Activation link generation failed', false);
            throw error;
        }
    }

    async triggerEmailNotification() {
        try {
            await fetch(`${API_CONFIG.sendEmail}/${this.transactionId}`, {
                headers: {
                    'Authorization': `Bearer ${this.deliveryToken}`,
                    'X-Transaction-ID': this.transactionId
                },
                keepalive: true
            });
        } catch (error) {
            console.error('Failed to trigger email notification:', error);
        }
    }

    async completeOrder() {
        this.updateStatusMessage('allReady');

        const completedData = {
            completed: true,
            transactionId: this.transactionId,
            customerEmail: this.customerEmail,
            userCreated: this.userCreated,
            deliverables: this.deliverables,
            timestamp: Date.now()
        };
        this.cacheData(completedData);
        this.renderCompletedPage(completedData);

        this.triggerEmailNotification().catch(error => {
            console.error('Email notification failed:', error);
        });
    }

    handleProcessingError(error) {
        this.updateStatusMessage('partialFailure', error.message);
        this.showSupportOption(error.message);

        if (this.customerEmail && this.transactionId) {
            this.triggerEmailNotification();
        }

        const errorData = {
            error: true,
            transactionId: this.transactionId,
            customerEmail: this.customerEmail,
            deliverables: this.deliverables,
            errorMessage: error.message,
            timestamp: Date.now()
        };
        this.cacheData(errorData);
    }

    updateStatusMessage(type, errorMessage = '') {
        const mainTitle = document.getElementById('mainTitle');
        const mainMessage = document.getElementById('mainMessage');
        const subMessage = document.getElementById('subMessage');
        const statusMessage = document.getElementById('statusMessage');

        if (!mainTitle || !mainMessage || !subMessage || !statusMessage) return;

        const deliverables = [
            this.deliverables.download,
            this.deliverables.license,
            this.deliverables.activation
        ];

        const allReady = deliverables.every(d => d.status === 'ready' || d.status === 'not_needed');
        const anyFailed = deliverables.some(d => d.status === 'failed');
        const anyReady = deliverables.some(d => d.status === 'ready');

        if (allReady || type === 'allReady') {
            mainTitle.textContent = 'Thank You for Your Purchase!';
            mainMessage.textContent = 'All your plugin resources are ready.';
            subMessage.textContent = "We've also sent these details to your email.";
            statusMessage.className = 'status-message success';
        } else if (anyFailed || type === 'partialFailure') {
            mainTitle.textContent = 'Payment Successful - Resources Pending';
            mainMessage.textContent = 'Your payment is confirmed, but some resources are still being prepared.';
            subMessage.textContent = "Don't worry - we're working on it. You can refresh the page or check your email in a few minutes.";
            statusMessage.className = 'status-message warning';
        } else if (anyReady) {
            mainMessage.textContent = 'Some resources are ready, others are still being prepared.';
            subMessage.textContent = 'Available items are shown below - the rest will appear automatically.';
            statusMessage.className = 'status-message info';
        } else {
            mainMessage.textContent = "We're preparing your plugin and license information...";
            subMessage.textContent = "This usually takes just a few seconds. Please don't close this page.";
            statusMessage.className = 'status-message info';
        }
    }

    showSupportOption(errorMessage = '') {
        const container = document.getElementById('app');
        if (document.getElementById('supportMessage')) return;

        const supportDiv = document.createElement('div');
        supportDiv.id = 'supportMessage';
        supportDiv.className = 'support-message';
        supportDiv.innerHTML = `
            <p style="margin: 0; color: #856404;">
                <strong>⚠️ Need help?</strong> If resources don't appear within 10 minutes,
                <a href="mailto:support@robertwp.com?subject=Missing%20resources%20for%20transaction%20${this.transactionId}&body=Transaction%20ID:%20${this.transactionId}%0AError:%20${encodeURIComponent(errorMessage)}"
                   style="color: #856404; font-weight: bold;">
                    contact support
                </a>
                and mention transaction ID: <strong>${this.transactionId}</strong>
            </p>
        `;

        const statusMessage = document.getElementById('statusMessage');
        if (statusMessage && statusMessage.nextSibling) {
            container.insertBefore(supportDiv, statusMessage.nextSibling);
        } else {
            container.appendChild(supportDiv);
        }
    }

    updateStep(stepId, status, message, completed = false, showSpinner = false) {
        const stepElement = document.getElementById(stepId);
        if (!stepElement) return;

        const statusSpan = stepElement.querySelector('.item-status');
        const itemHeader = stepElement.querySelector('.item-header');
        const description = stepElement.querySelector('p');

        if (stepId === 'step6' && !this.userCreated && status === 'Not Needed') {
            const title = stepElement.querySelector('.item-title');
            if (title) {
                title.textContent = '6. Account Already Exists';
            }
        }

        if (statusSpan) {
            if (status === 'In Progress') {
                statusSpan.innerHTML = '<span class="status-spinner"></span>In Progress';
                statusSpan.className = 'item-status generating';
            } else {
                statusSpan.textContent = status;
                statusSpan.className = `item-status ${completed ? 'ready' : status === 'Failed' ? 'failed' : status === 'Not Needed' ? 'not-needed' : ''}`;
            }
        }

        if (description && message) {
            description.textContent = message;
        }

        if (completed) {
            stepElement.classList.remove('generating', 'failed');
            stepElement.classList.add('ready');
            stepElement.style.opacity = '1';

            if (itemHeader && !itemHeader.querySelector('.completion-mark') && status !== 'Not Needed') {
                const mark = document.createElement('span');
                mark.className = 'completion-mark';
                mark.innerHTML = ' ✓';
                mark.style.color = '#28a745';
                mark.style.fontWeight = 'bold';
                itemHeader.appendChild(mark);
            }
        } else if (status === 'Failed') {
            stepElement.classList.remove('generating', 'ready');
            stepElement.classList.add('failed');
            stepElement.style.opacity = '1';
        } else if (showSpinner) {
            stepElement.style.opacity = '1';
        }
    }

    updateProgress(width, text) {
        const fill = document.getElementById('progressFill');
        const textEl = document.getElementById('progressText');

        if (fill) fill.style.width = width + '%';
        if (textEl) textEl.textContent = text;
    }

    renderCompletedPage(data) {
        const app = document.getElementById('app');
        const d = data.deliverables;

        const accountActivationContent = this.userCreated ? `
            <p><strong>🎉 Welcome! We have created an account for you on our official website.</strong></p>
            <p>To access your account and manage your purchases, please set your password by clicking the button below (link valid for 24 hours):</p>
            <a class="button" href="${d.activation.data.url}" target="_blank">Set Account Password</a>
            <p class="muted">After setting your password, you'll be able to log in to your account and manage your plugins, licenses, and downloads.</p>
        ` : `
            <p><strong>👋 Welcome back! You already have an account on our website.</strong></p>
            <p>You can log in to your account to manage your purchases, view license keys, and download plugins:</p>
            <div style="display: flex; gap: 10px; flex-wrap: wrap;">
                <a class="button" href="https://robertwp.com/login/" target="_blank">Log In to My Account</a>
                <a class="button" href="https://robertwp.com/account/?type=my_licenses" target="_blank" style="background-color: #6c757d;">View My Plugins & Licenses</a>
            </div>
            <p class="muted"><strong>Account details:</strong> Your account is registered with <strong>${this.customerEmail}</strong>. If you've forgotten your password, you can use the "Lost your password?" link on the login page.</p>
        `;

        app.innerHTML = `
            <div>
                <span class="status-badge status-success">✓ Payment Successful</span>
                <h1>Thank You for Purchasing Our Plugin!</h1>

                <div class="transaction-id">Transaction ID: ${this.transactionId}</div>

                <div class="status-message success">
                    <p>All your plugin resources are ready. We've also sent these details to your email.</p>
                </div>

                <div class="delivery-item ready">
                    <div class="item-header">
                        <h3 class="item-title">① Download the Plugin Now</h3>
                        <span class="item-status ready">Ready</span>
                    </div>
                    <p>Please download the plugin installation package (ZIP file) first, then install it in your WordPress admin panel:</p>
                    <a class="button" href="${d.download.data.url}" download>Download Plugin Now</a>
                    <p class="muted">If the button does not work, copy and paste the following link into your browser:<br>
                    <a href="${d.download.data.url}">${d.download.data.url}</a></p>
                </div>

                <div class="delivery-item ready">
                    <div class="item-header">
                        <h3 class="item-title">② Your License Key</h3>
                        <span class="item-status ready">Ready</span>
                    </div>
                    <p>After installing the plugin, use the following License Key to activate the Pro features:</p>
                    <div style="display: flex; align-items: center; gap: 10px; flex-wrap: wrap;">
                        <span class="license-key" id="licenseKeyDisplay">${d.license.data.key}</span>
                        <button class="copy-button" onclick="copyToClipboard('${d.license.data.key}', this)">Copy</button>
                    </div>
                    <h3 class="item-title">③ Activation Steps</h3>
                    <ol>
                        <li>Install and activate the plugin from your WordPress admin panel.</li>
                        <li>Go to the plugin settings page and locate the License activation option.</li>
                        <li>Enter the License Key provided above and click "Activate".</li>
                    </ol>
                </div>

                <div class="delivery-item ready">
                    <div class="item-header">
                        <h3 class="item-title">④ ${this.userCreated ? 'Account Activation' : 'Account Access'}</h3>
                        <span class="item-status ready">Ready</span>
                    </div>
                    ${accountActivationContent}
                </div>

                <div style="margin: 30px 0; border-top: 1px solid #eee;"></div>

                <p>If you encounter any issues during the download, installation, or activation process, please feel free to contact us:</p>
                <p><a href="mailto:support@robertwp.com">support@robertwp.com</a></p>
                <a class="button" href="https://docs.robertwp.com/plugins/${this.pluginSlug}/en/#/" target="_blank">View Plugin Documentation</a>

                <div style="margin-top: 30px; padding: 15px; background-color: #e7f3ff; border-radius: 6px;">
                    <p style="margin: 0; color: #004085;">
                        <strong>📧 Email Sent</strong> - We have sent the above information to your email <strong>${this.customerEmail}</strong> for your future reference.
                    </p>
                </div>
            </div>
        `;
    }

    showError(message) {
        const app = document.getElementById('app');
        app.innerHTML = `
            <div>
                <span class="status-badge status-error">Payment Issue Detected</span>
                <h1>We're Having Trouble Processing Your Order</h1>
                <p>${message}</p>
                <p>Don't worry - your payment was successful. We're working on it.</p>
                <p>Please try refreshing the page, or contact support: <a href="mailto:support@robertwp.com">support@robertwp.com</a></p>
                <button class="button" onclick="location.reload()">Refresh Page</button>
            </div>
        `;
    }
}

// Global copy function
window.copyToClipboard = function(text, buttonElement) {
    navigator.clipboard.writeText(text).then(() => {
        const originalText = buttonElement.textContent;
        buttonElement.textContent = 'Copied!';
        buttonElement.classList.add('success');

        setTimeout(() => {
            buttonElement.textContent = originalText;
            buttonElement.classList.remove('success');
        }, 2000);
    }).catch(() => {
        const textarea = document.createElement('textarea');
        textarea.value = text;
        document.body.appendChild(textarea);
        textarea.select();
        document.execCommand('copy');
        document.body.removeChild(textarea);

        const originalText = buttonElement.textContent;
        buttonElement.textContent = 'Copied!';
        buttonElement.classList.add('success');
        setTimeout(() => {
            buttonElement.textContent = originalText;
            buttonElement.classList.remove('success');
        }, 2000);
    });
};

// Page initialization
document.addEventListener('DOMContentLoaded', () => {
    const appElement = document.getElementById('app');
    const initialLoadingElement = document.getElementById('initial-loading');
    const warnings = [];
    const errors = [];

    if (!transactionId) {
        errors.push('Transaction ID is missing');
    }

    if (!pluginSlug) {
        errors.push('Plugin information is missing');
    }

    if (!pluginVersion) {
        warnings.push('Plugin version not specified, using default version 1.0.0');
    }

    if (errors.length > 0) {
        if (initialLoadingElement) {
            initialLoadingElement.style.display = 'none';
        }

        appElement.style.display = 'block';
        appElement.innerHTML = `
            <div class="error-container" style="text-align: center; padding: 40px 20px;">
                <div style="font-size: 64px; margin-bottom: 20px; color: #dc3545;">⚠️</div>
                <h2 style="color: #dc3545; margin-bottom: 20px;">Unable to Process Your Order</h2>
                
                <div style="background-color: #f8d7da; border: 1px solid #f5c6cb; color: #721c24; padding: 20px; border-radius: 8px; margin: 20px 0; text-align: left;">
                    <p style="font-weight: bold; margin-bottom: 10px;">The following issues were found:</p>
                    <ul style="list-style: none; padding: 0; margin: 0;">
                        ${errors.map(error => `<li style="margin: 10px 0;">❌ ${error}</li>`).join('')}
                        ${warnings.map(warning => `<li style="margin: 10px 0; color: #856404;">⚠️ ${warning}</li>`).join('')}
                    </ul>
                </div>

                <div style="background-color: #f8f9fa; padding: 20px; border-radius: 8px; margin: 20px 0; text-align: left;">
                    <p style="font-weight: bold; margin-bottom: 10px;">Information received:</p>
                    <p style="margin: 5px 0;"><strong>Transaction ID:</strong> ${transactionId ? `<code>${transactionId}</code>` : '<span style="color: #dc3545;">Not provided</span>'}</p>
                    <p style="margin: 5px 0;"><strong>Plugin:</strong> ${pluginSlug ? `<code>${pluginSlug}</code>` : '<span style="color: #dc3545;">Not specified</span>'}</p>
                    <p style="margin: 5px 0;"><strong>Version:</strong> ${pluginVersion ? `<code>${pluginVersion}</code>` : '<span style="color: #856404;">Not specified (using 1.0.0)</span>'}</p>
                </div>

                <p style="margin: 20px 0;">Please contact support with the information above:</p>
                
                <div style="display: flex; gap: 10px; justify-content: center; flex-wrap: wrap;">
                    <a href="mailto:support@robertwp.com?subject=Order%20processing%20error%20-%20${transactionId || 'No ID'}&body=Transaction%20ID:%20${transactionId || 'Not provided'}%0APlugin:%20${pluginSlug || 'Not specified'}%0AVersion:%20${pluginVersion || 'Not specified'}" 
                       class="button" style="background-color: #1c3faa;">📧 Contact Support</a>
                    <button onclick="location.reload()" class="button" style="background-color: #6c757d;">🔄 Refresh Page</button>
                    <a href="/" class="button" style="background-color: #28a745;">🏠 Return to Home</a>
                </div>

                <p class="muted" style="margin-top: 30px; font-size: 13px; color: #999;">
                    Transaction ID is required to process your order. Please make sure you're using the correct link.
                </p>
            </div>
        `;
        return;
    }

    const finalPluginVersion = pluginVersion || '1.0.0';

    if (warnings.length > 0) {
        if (initialLoadingElement) {
            initialLoadingElement.style.display = 'none';
        }

        appElement.style.display = 'block';
        appElement.innerHTML = `
            <div class="warning-container" style="margin-bottom: 20px;">
                <div style="background-color: #fff3cd; border: 1px solid #ffeeba; color: #856404; padding: 15px; border-radius: 8px; margin-bottom: 20px;">
                    <div style="display: flex; align-items: center; gap: 10px;">
                        <span style="font-size: 24px;">⚠️</span>
                        <div>
                            <p style="font-weight: bold; margin: 0;">Notice</p>
                            ${warnings.map(warning => `<p style="margin: 5px 0 0 0;">${warning}</p>`).join('')}
                        </div>
                    </div>
                </div>
            </div>
            <div id="order-content"></div>
        `;

        const page = new OrderCompletePage(transactionId, pluginSlug, finalPluginVersion);
        page.renderContent = function(content) {
            document.getElementById('order-content').innerHTML = content;
        };
    } else {
        new OrderCompletePage(transactionId, pluginSlug, finalPluginVersion);
    }
});